// Init: PKCE generieren, Authorize-URL bauen
const crypto = require('crypto');

const CLIENT_ID = $env.CANVA_CLIENT_ID;
if (!CLIENT_ID) throw new Error('Env CANVA_CLIENT_ID fehlt');

const REDIRECT_URI = 'https://n8n.srv1099163.hstgr.cloud/webhook/canva-oauth-callback';
const SCOPE = 'design:meta:read design:content:read design:content:write asset:read';

// PKCE: random verifier (43-128 chars, URL-safe)
const codeVerifier = crypto.randomBytes(48).toString('base64url');
const codeChallenge = crypto.createHash('sha256').update(codeVerifier).digest('base64url');
const state = crypto.randomBytes(16).toString('hex');

// Verifier in workflow staticData speichern
const sd = $getWorkflowStaticData('global');
sd.canva_code_verifier = codeVerifier;
sd.canva_oauth_state = state;
sd.canva_init_at = new Date().toISOString();

const authorizeUrl = 'https://www.canva.com/api/oauth/authorize?'
  + 'client_id=' + encodeURIComponent(CLIENT_ID)
  + '&redirect_uri=' + encodeURIComponent(REDIRECT_URI)
  + '&response_type=code'
  + '&scope=' + encodeURIComponent(SCOPE)
  + '&state=' + state
  + '&code_challenge=' + codeChallenge
  + '&code_challenge_method=S256';

return [{ json: {
  authorize_url: authorizeUrl,
  hinweis: 'Diese URL im Browser öffnen, bei Canva zustimmen. Canva redirected dann zum Callback-Webhook.',
  pkce_verifier_saved: true,
  state
}}];

// Callback: Code von Canva empfangen, gegen Token tauschen
const CLIENT_ID = $env.CANVA_CLIENT_ID;
const CLIENT_SECRET = $env.CANVA_CLIENT_SECRET;
if (!CLIENT_ID || !CLIENT_SECRET) throw new Error('Env CANVA_CLIENT_ID/SECRET fehlt');

const REDIRECT_URI = 'https://n8n.srv1099163.hstgr.cloud/webhook/canva-oauth-callback';

const query = $input.item.json.query ?? {};
const code = query.code;
const state = query.state;
const error = query.error;

if (error) throw new Error('Canva OAuth-Fehler: ' + error + ' - ' + (query.error_description ?? ''));
if (!code) throw new Error('Kein code im Callback');

const sd = $getWorkflowStaticData('global');
const codeVerifier = sd.canva_code_verifier;
if (!codeVerifier) throw new Error('Kein code_verifier in staticData. WF-08 Init zuerst ausführen.');

// Optional state-check
if (sd.canva_oauth_state && state !== sd.canva_oauth_state) {
  throw new Error('State-Mismatch: erwartet ' + sd.canva_oauth_state + ', bekommen ' + state);
}

return [{ json: {
  code,
  code_verifier: codeVerifier,
  client_id: CLIENT_ID,
  client_secret: CLIENT_SECRET,
  redirect_uri: REDIRECT_URI,
  basic_auth: 'Basic ' + Buffer.from(CLIENT_ID + ':' + CLIENT_SECRET).toString('base64')
}}];

// Token speichern in staticData
const resp = $input.item.json;
if (!resp.access_token) throw new Error('Kein access_token in Canva-Response: ' + JSON.stringify(resp));

const sd = $getWorkflowStaticData('global');
sd.canva_access_token  = resp.access_token;
sd.canva_refresh_token = resp.refresh_token;
sd.canva_token_type    = resp.token_type ?? 'Bearer';
sd.canva_expires_in    = resp.expires_in ?? 14400;
sd.canva_obtained_at   = new Date().toISOString();
sd.canva_expires_at    = new Date(Date.now() + (resp.expires_in ?? 14400) * 1000).toISOString();

// Verifier ist verbraucht
sd.canva_code_verifier = null;

return [{ json: {
  ok: true,
  message: 'Canva Access Token erhalten und gespeichert',
  expires_at: sd.canva_expires_at,
  has_refresh_token: !!sd.canva_refresh_token,
  access_token_preview: resp.access_token.slice(0, 20) + '…'
}}];

