// Refresh: Token erneuern
const CLIENT_ID = $env.CANVA_CLIENT_ID;
const CLIENT_SECRET = $env.CANVA_CLIENT_SECRET;
if (!CLIENT_ID || !CLIENT_SECRET) throw new Error('Env fehlen');

const sd = $getWorkflowStaticData('global');
const refreshToken = sd.canva_refresh_token;
if (!refreshToken) throw new Error('Kein Refresh-Token. WF-08 Init+Callback zuerst durchlaufen.');

return [{ json: {
  refresh_token: refreshToken,
  basic_auth: 'Basic ' + Buffer.from(CLIENT_ID + ':' + CLIENT_SECRET).toString('base64')
}}];

// Refreshten Token speichern
const resp = $input.item.json;
if (!resp.access_token) throw new Error('Kein access_token im Refresh-Response: ' + JSON.stringify(resp));

const sd = $getWorkflowStaticData('global');
sd.canva_access_token  = resp.access_token;
if (resp.refresh_token) sd.canva_refresh_token = resp.refresh_token;
sd.canva_expires_in    = resp.expires_in ?? 14400;
sd.canva_obtained_at   = new Date().toISOString();
sd.canva_expires_at    = new Date(Date.now() + (resp.expires_in ?? 14400) * 1000).toISOString();

return [{ json: {
  ok: true,
  message: 'Canva Access Token refreshed',
  expires_at: sd.canva_expires_at
}}];

// Aktuellen Token aus staticData lesen und zurückgeben
const sd = $getWorkflowStaticData('global');
const token = sd.canva_access_token;

if (!token) {
  return [{ json: {
    ok: false,
    error: 'Kein Token gespeichert. WF-08 Init+Callback durchlaufen.'
  }}];
}

const expiresAt = sd.canva_expires_at;
const isExpired = expiresAt && new Date(expiresAt) < new Date();

return [{ json: {
  ok: !isExpired,
  access_token: token,
  expires_at: expiresAt,
  is_expired: isExpired,
  needs_refresh: isExpired
}}];
